#ifdef __cplusplus
extern "C" {
#endif

#include <stdio.h>
#include <stdlib.h>
#include <sys/time.h>
#include <cuda_runtime.h>

#define fp double

#define NUMBER_PAR_PER_BOX 100

#ifdef RD_WG_SIZE_0_0
#define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define NUMBER_THREADS RD_WG_SIZE
#else
#define NUMBER_THREADS 128
#endif

typedef struct {
    fp x, y, z;
} THREE_VECTOR;

typedef struct {
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str {
    fp alpha;
} par_str;

typedef struct dim_str {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

extern "C" __global__
void kernel_gpu_cuda(par_str d_par_gpu,
                     dim_str d_dim_gpu,
                     box_str *d_box_gpu,
                     FOUR_VECTOR *d_rv_gpu,
                     fp *d_qv_gpu,
                     FOUR_VECTOR *d_fv_gpu);

extern int platform_id_inuse;
extern int device_id_inuse;

static double elapsed_ms(const struct timeval *end, const struct timeval *start) {
    return (double)(end->tv_sec - start->tv_sec) * 1000.0 +
           (double)(end->tv_usec - start->tv_usec) / 1000.0;
}

void kernel_gpu_cuda_wrapper(par_str par_cpu,
                             dim_str dim_cpu,
                             box_str* box_cpu,
                             FOUR_VECTOR* rv_cpu,
                             fp* qv_cpu,
                             FOUR_VECTOR* fv_cpu)
{
#ifdef TIMING
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_mem_alloc_end;
    struct timeval tv_h2d_end;
    struct timeval tv_kernel_end;
    struct timeval tv_d2h_end;
    struct timeval tv_close_start, tv_close_end;
    double init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0;
    double d2h_time = 0, close_time = 0, total_time = 0;
    gettimeofday(&tv_total_start, NULL);
#endif

    int dev_count = 0;
    cudaGetDeviceCount(&dev_count);
    int dev = 0;
    if (device_id_inuse >= 0 && device_id_inuse < dev_count) dev = device_id_inuse;
    cudaSetDevice(dev);

    cudaDeviceProp prop;
    cudaGetDeviceProperties(&prop, dev);

    printf("Platform: NVIDIA CUDA\n");
    printf("Device: %s\n", prop.name);

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    init_time = elapsed_ms(&tv_init_end, &tv_total_start);
#endif

    size_t local_work_size[1];
    local_work_size[0] = NUMBER_THREADS;
    size_t global_work_size[1];
    global_work_size[0] = (size_t)dim_cpu.number_boxes * local_work_size[0];

    printf("# of blocks = %lu, # of threads/block = %lu (ensure that device can handle)\n",
           (unsigned long)(global_work_size[0] / local_work_size[0]),
           (unsigned long)local_work_size[0]);

    box_str *d_box_gpu = NULL;
    FOUR_VECTOR *d_rv_gpu = NULL;
    fp *d_qv_gpu = NULL;
    FOUR_VECTOR *d_fv_gpu = NULL;

    cudaMalloc((void**)&d_box_gpu, dim_cpu.box_mem);
    cudaMalloc((void**)&d_rv_gpu, dim_cpu.space_mem);
    cudaMalloc((void**)&d_qv_gpu, dim_cpu.space_mem2);
    cudaMalloc((void**)&d_fv_gpu, dim_cpu.space_mem);

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    mem_alloc_time = elapsed_ms(&tv_mem_alloc_end, &tv_init_end);
#endif

    cudaMemcpy(d_box_gpu, box_cpu, dim_cpu.box_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_rv_gpu, rv_cpu, dim_cpu.space_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_qv_gpu, qv_cpu, dim_cpu.space_mem2, cudaMemcpyHostToDevice);
    cudaMemcpy(d_fv_gpu, fv_cpu, dim_cpu.space_mem, cudaMemcpyHostToDevice);

#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    h2d_time = elapsed_ms(&tv_h2d_end, &tv_mem_alloc_end);
#endif

    kernel_gpu_cuda<<<(unsigned int)dim_cpu.number_boxes, NUMBER_THREADS>>>(
        par_cpu, dim_cpu, d_box_gpu, d_rv_gpu, d_qv_gpu, d_fv_gpu);
    cudaDeviceSynchronize();

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    kernel_time = elapsed_ms(&tv_kernel_end, &tv_h2d_end);
#endif

    cudaMemcpy(fv_cpu, d_fv_gpu, dim_cpu.space_mem, cudaMemcpyDeviceToHost);

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    d2h_time = elapsed_ms(&tv_d2h_end, &tv_kernel_end);
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    cudaFree(d_rv_gpu);
    cudaFree(d_qv_gpu);
    cudaFree(d_fv_gpu);
    cudaFree(d_box_gpu);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    close_time = elapsed_ms(&tv_close_end, &tv_close_start);
    total_time = elapsed_ms(&tv_total_end, &tv_total_start);
    gettimeofday(&tv_total_end, NULL);
    total_time = elapsed_ms(&tv_total_end, &tv_total_start);

    printf("Time spent in different stages of the application:\n");
    printf("Init: %f\n", (float)init_time);
    printf("MemAlloc: %f\n", (float)mem_alloc_time);
    printf("HtoD: %f\n", (float)h2d_time);
    printf("Exec: %f\n", (float)kernel_time);
    printf("DtoH: %f\n", (float)d2h_time);
    printf("Close: %f\n", (float)close_time);
    printf("Total: %f\n", (float)total_time);
#endif
}

#ifdef __cplusplus
}
#endif
